            var targetDicts = new[]
            {
                new Dictionary<string, object> { { "EntryA", new object() } },
                new Dictionary<string, object> { { "EntryB", new object() } }
            };
            bool registeredForCleanup = true;

            // Take a snapshot of initial dictionary state
            var snapshot = targetDicts
                .Select(d => new Dictionary<string, object>(d))
                .ToArray();

            // Act
